import{_ as r}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a0 as o,a2 as d,a1 as m,C as a}from"./framework-a4c02b8f.js";const f={},u=e("figure",null,[e("img",{src:r,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/c14d78fc52bdedf18b89611eb32e5353.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=m('<hr><p>作为寂寞的独居夜晚的陪伴，养宠物也并不少见吧。</p><p>例如狗和猫。它们不仅可爱、可以治愈孤独，还能激发「作为主人的责任感」，并有助于养成规律的独居生活习惯，远离颓废的倾向……似乎是这样的！</p><p>养狗或养猫需要调整生活节奏，管理饲料和排泄，及时回家查看情况等。正因为背负着生命的重负，饲养者的人性也得以提升……似乎是这样的！</p><p>「似乎」是因为我从未养过狗或猫，所以这些都是我听别人说的。然而，我养过塔兰图拉毒蛛（タランチュラ）。因此，我可以谈论有蜘蛛的生活。</p><p>首先，蜘蛛非常安静。它们不动，只在盒子里筑起薄薄的巢穴，然后静静地待在那里，不发出任何声音。而作为饲料跳跃在地上的的蟋蟀则很吵闹。蜘蛛除了默默地等待蟋蟀被它们的网困住之外，没有其他行动。这种冷静感很好。虫子没有情感。</p><p>因为它们没有情感，所以它们也不会对人类产生亲近感。它们只是按照本能重复进食，所以只能偶尔将它们放在手臂上。对它们来说，这只是「场所」发生了变化，它们会按照本能试图爬到更高的地方，因而沿着手臂向上爬。如果你不好好控制「高度」，它们可能会迅速爬到你的脸上，让你感到恐慌。你可以将拳头抬到空中，引导它们去最高的地方，也就是拳头。处理蜘蛛的方式，就只有这些了。此外，因为只会造成压力，所以最好不要将它们放在手上。</p><p>饲养方法也非常简单。只需控制温度，剩下的就是放入水和蟋蟀，然后放置着就可以了。一周只需添加一次蟋蟀。此外，如果蜘蛛蜕皮了，需要清理一下蜕皮。虽然不能否认地会产生一定的「依恋」，但像狗或猫一样能够相互认知并进行交流的事是绝对不会发生的。也就是说，尽管住在一起，但双方都是孤独的。</p><p>对于人类来说，只提供最低限度的饲料和清理，其他时间只是观察蜘蛛探出巢穴的部分。对于蜘蛛来说，为了答谢饲料和清理，它们会短暂地展现自己。除此之外，它们连一丁点的声音都不会发出，不会打扰我们的生活。没有安慰，也没有爱的痕迹。孤独与孤独之间相互碰撞。这就是蜘蛛的饲养。</p><p>不是彼此分享孤独，而是各自孤独的事实持续存在的夜晚。作为能让我们一起体验这种寂寞的存在，塔兰图拉毒蛛今晚也只是静静地在盒子中的巢穴上等待着猎物。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/2679d43064186f78440d630d4df14eb1.JPG" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/461b53173d49e092d7b13579634c4153.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【闪闪发光的盖刚（ガイガン）与King Joe的软胶玩具】怪兽软胶玩具未开封才有味道，所以一直忍着不打开保存起来。但我决定还是要亲眼看到这闪闪发光的光彩，于是我打开了。真是让人大大满足的宝石般的闪耀。</p></blockquote>',13);function g(x,y){const n=a("ExternalLinkIcon"),l=a("RouterLink");return c(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第9回／蜘蛛を飼う"),o(n)])]),e("blockquote",null,[k,e("p",null,[o(l,{to:"/posts/Translate/nyalra_kb_08.html"},{default:d(()=>[t("【奈亚拉面壁自语】第08回｜男人在孤独的夜晚都做些什么呢【220110】")]),_:1})])]),b])}const z=s(f,[["render",g],["__file","nyalra_kb_09.html.vue"]]);export{z as default};
